import React from "react";
import mpl from "./img/mpl-demo.png";
import gmd from "./img/gmd-demo.png";
import lv from "./img/lv-demo.png";
import python from "./img/python.png";
import matplotlib from "./img/matplotlib.png";
import js from "./img/js.png";
import socket from "./img/socket.png";
import html from "./img/html.png";
import java from "./img/java.png";

export default function Proj() {
  function ProjInstance(props) {
    return (
      <div>
        <a href={props.site}>
          <h3 style={{ marginBlockStart: "0", marginBlockEnd: "0.5em" }}>
            {props.name}
          </h3>
        </a>
        <i>{props.time}</i>
        <div>{props.children}</div>
      </div>
    );
  }

  return (
    <div className="Proj">
      <h2>My Past Projects</h2>
      <div className="container">
        <div className="a-proj">
          <div className="proj-pic">
            <img alt="" src={mpl} />
          </div>
          <div className="proj-title">
            <ProjInstance
              name="Subplot Visibility Checkbox"
              time="Jan - Apr 2020"
              site="https://github.com/Talukder0429/matplotlib_legend_checkbox"
            >
              <div style={{ marginTop: "0.5rem" }}>
                <img alt="" className="tech-used" src={python} />
                <img alt="" className="tech-used" src={matplotlib} />
              </div>
            </ProjInstance>
          </div>
          <div className="proj-info">
            A Matplotlib extension which adds checkboxes corresponding to the
            visibility of subplots. This is primarily used for toggling
            visibility of subplots on the fly without recompiling code.
          </div>
        </div>
        <div className="a-proj">
          <div className="proj-pic">
            <img alt="" src={gmd} />
          </div>
          <div className="proj-title">
            <ProjInstance
              name="GuessMyDrawing.io"
              time="Jan - Apr 2019"
              site="https://github.com/Talukder0429/guessmydrawing-io"
            >
              <div style={{ marginTop: "0.5rem" }}>
                <img alt="" className="tech-used" src={js} />
                <img alt="" className="tech-used" src={socket} />
                <img alt="" className="tech-used" src={html} />
              </div>
            </ProjInstance>
          </div>
          <div className="proj-info">
            A modern spin on the classic Pictionary. In this online multiplayer
            game, players take turn drawing and guessing. Guessing the right
            answer quickly will yielding more points for both the artist and the
            guesser.
          </div>
        </div>
        <div className="a-proj">
          <div className="proj-pic">
            <img alt="" src={lv} />
          </div>
          <div className="proj-title">
            <ProjInstance
              name="La Vite"
              time="Sep - Dec 2018"
              site="https://github.com/Talukder0429/La-Vite"
            >
              <div style={{ marginTop: "0.5rem" }}>
                <img alt="" className="tech-used" src={java} />
                <img alt="" className="tech-used" src={js} />
              </div>
            </ProjInstance>
          </div>
          <div className="proj-info">
            This application was intended for use by Toronto East Quadrant Local
            Immigration Partnership (TEQ LIP) as a solution to digitalize client
            information. The program is able to add new clients, modify/remove
            existing entries, and produce detailed reports.
          </div>
        </div>
      </div>
    </div>
  );
}
