import React from "react";
import email from "./img/email.png";
import li from "./img/li.png";
import gh from "./img/gh.png";

export default function Contact() {
  return (
    <div className="Contact">
      <h2>Contact Me</h2>
      <h3>Have a question or want to work together?</h3>
      <h3>You can reach me using the methods below:</h3>
      <div className="container">
        <a href="mailto:arnob_talukder@hotmail.com">
          <img alt="" src={email} />
        </a>
        <a href="https://www.linkedin.com/in/talukder0429/">
          <img alt="" src={li} />
        </a>
        <a href="https://github.com/talukder0429">
          <img alt="" src={gh} />
        </a>
      </div>
    </div>
  );
}
