import React, { useState } from "react";

export default function Exp() {
  const [exp, setExp] = useState(0);

  function ExpInstance(props) {
    return (
      <div className="exp-info">
        <h3 style={{ marginBlockStart: "0", marginBlockEnd: "0.5em" }}>
          {props.pos}
        </h3>
        <i>{props.time}</i>
        <ul style={{ marginBottom: "0" }}>{props.children}</ul>
      </div>
    );
  }

  return (
    <div className="Exp">
      <h2>Where I’ve Worked</h2>
      <div className="container">
        <div className="pick-exp">
          <button
            className={exp === 0 ? "exp-select exp-active" : "exp-select"}
            onClick={() => setExp(0)}
          >
            BCCS
          </button>
          <button
            className={exp === 1 ? "exp-select exp-active" : "exp-select"}
            onClick={() => setExp(1)}
          >
            KTA
          </button>
          <button
            className={exp === 2 ? "exp-select exp-active" : "exp-select"}
            onClick={() => setExp(2)}
          >
            HP
          </button>
          <button
            className={exp === 3 ? "exp-select exp-active" : "exp-select"}
            onClick={() => setExp(3)}
          >
            IPWORLD
          </button>
        </div>
        <div className="picked-exp">
          <div style={{ display: exp === 0 ? "block" : "none" }}>
            <ExpInstance
              pos="Web Developer - Bangladesh Centre & Community Services"
              time="June - Nov 2020"
            >
              <li>
                Revamped the NFP{" "}
                <a href="https://www.bangladeshcentre.ca/">website</a> for
                greater accessibility for mobile and multi-lingual users.
              </li>
              <li>
                Setup donation systems through CanadaHelps and PayPal, and
                integrated them onto the website through their respective REST
                APIs.
              </li>
              <li>
                Setup a robust system to collate visual media from social events
                for display during future events.
              </li>
            </ExpInstance>
          </div>
          <div style={{ display: exp === 1 ? "block" : "none" }}>
            <ExpInstance
              pos="Computer Technical Specialist - Kennedy Tax"
              time="Feb 2017 - May 2021 (seasonally)"
            >
              <li>
                Setup and maintain automation of common tasks and batch client
                communications.
              </li>
              <li>
                Develop and update the business{" "}
                <a href="https://kennedyaccounting.ca/">website</a>, providing
                up-to-date information for clients.
              </li>
              <li>
                Maintain workplace network and storage solutions, and help
                integrate new users into the office network.
              </li>
            </ExpInstance>
          </div>
          <div style={{ display: exp === 2 ? "block" : "none" }}>
            <ExpInstance
              pos="Field Specialist - HP"
              time="Oct 2016 - July 2020"
            >
              <li>
                Provided education on the full suite of HP products to meet the
                individual needs of customers.
              </li>
              <li>
                Guided customers through the sales process from intercept to
                checkout.
              </li>
              <li>
                Maintained strong relationships with store personnel; ensuring
                continued partnership between the store and HP.
              </li>
            </ExpInstance>
          </div>
          <div style={{ display: exp === 3 ? "block" : "none" }}>
            <ExpInstance
              pos="Computer Support and Repair - IPWorld"
              time="Feb - Sep 2016"
            >
              <li>
                Overhauled the business{" "}
                <a href="http://www.ipworld.ca/">website</a> to ensure a more
                responsive mobile experience.
              </li>
              <li>
                Created and maintained a Linux-based server for streaming videos
                and live broadcasts.
              </li>
              <li>
                Performed technical maintenance on laptops and desktops for
                individuals and small businesses.
              </li>
            </ExpInstance>
          </div>
        </div>
      </div>
    </div>
  );
}
