import { useState } from "react";
import { Link } from "react-scroll";

export default function Nav() {
  const [navOpen, setNavOpen] = useState(false);

  function CusLink(props) {
    return (
      <Link
        href=""
        to={props.to}
        smooth={true}
        duration={500}
        onClick={() => setNavOpen(false)}
      >
        {props.children}
      </Link>
    );
  }

  return (
    <div className="Nav">
      <div className="container">
        <button onClick={() => setNavOpen(!navOpen)}>
          <span />
          <span />
          <span />
        </button>
        <ul className={navOpen ? "active" : ""} style={{}}>
          <li>
            <CusLink to="home">Home</CusLink>
          </li>
          <li>
            <CusLink to="exp">Experiences</CusLink>
          </li>
          <li>
            <CusLink to="skill">Skills</CusLink>
          </li>
          <li>
            <CusLink to="proj">Projects</CusLink>
          </li>
          <li>
            <CusLink to="contact">Contact</CusLink>
          </li>
        </ul>
      </div>
    </div>
  );
}
